            action: 'raw',
            sql: `CREATE TABLE users (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                name TEXT NOT NULL,
                email TEXT UNIQUE
            )`
        });
    },
    async down(db) {
        await db.adapter.dropTable('users');
    }
});

