        id:    { type: TYPES.INTEGER, primaryKey: true, autoIncrement: true },
        name:  { type: TYPES.STRING, required: true, maxLength: 100 },
        email: { type: TYPES.STRING, required: true, unique: true },
    };
    static timestamps = true;
}

// seeders/UsersSeeder.js
const { Seeder, Factory, Fake } = require('zero-http');
const User = require('../models/User');

class UsersSeeder extends Seeder
{
    async run(db) {
        const factory = new Factory(User);
        factory.define({
            name:  () => Fake.fullName(),
            email: () => Fake.email({ unique: true }),
            role:  'user',
        });

        await factory.count(20).create();

        // create a few admins
        factory.state('admin', { role: 'admin' });
        await factory.count(3).withState('admin').create();
    }
}

module.exports = UsersSeeder;

